import{_ as t,o as s,c as o,a0 as a}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Enterprise Readiness Assessment","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise-readiness.md","filePath":"enterprise-readiness.md","lastUpdated":1784483059000}'),n={name:"enterprise-readiness.md"};function i(d,e,r,c,l,h){return s(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="enterprise-readiness-assessment" tabindex="-1">Enterprise Readiness Assessment <a class="header-anchor" href="#enterprise-readiness-assessment" aria-label="Permalink to &quot;Enterprise Readiness Assessment&quot;">​</a></h1><p>Status of <code>@enterprise/vue-iframe-wrapper</code> v1.0.0 against the standard bar for an enterprise-consumed internal package (governance, quality, security, release engineering, support), plus a phased plan to close the remaining gaps — ordered <strong>easiest → hardest</strong>, not by business value. For value-ordered recommendations see <a href="/feature-recommendations"><code>FEATURE_RECOMMENDATIONS.md</code></a>; the two documents overlap in places (Playwright, accessibility, Nuxt) but answer different questions: that one asks &quot;what should we build next&quot;, this one asks &quot;what&#39;s blocking sign-off&quot;.</p><hr><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><p><em>Updated after implementing Phases 1-3 below.</em></p><table tabindex="0"><thead><tr><th>Area</th><th>Item</th><th>Status</th></tr></thead><tbody><tr><td><strong>Quality</strong></td><td>Unit/component test suite (Vitest + Vue Test Utils)</td><td>✅ 47 tests (incl. accessibility suite)</td></tr><tr><td></td><td>Coverage gate enforced in CI</td><td>✅ 90% statements/branches/functions/lines</td></tr><tr><td></td><td>Mutation testing</td><td>✅ Stryker, scoped to <code>src/utils</code> + <code>src/composables</code>; ~86%/~82% scores — see <a href="/guide/testing">Testing</a></td></tr><tr><td></td><td>Strict TypeScript, no <code>any</code></td><td>✅ ESLint rule enforced</td></tr><tr><td></td><td>Lint + format enforced in CI</td><td>✅ ESLint + Prettier</td></tr><tr><td><strong>Documentation</strong></td><td>README, getting started, examples</td><td>✅</td></tr><tr><td></td><td>Full API / parameter reference</td><td>✅ <code>PARAMETERS.md</code> + VitePress</td></tr><tr><td></td><td>Security model documented</td><td>✅ <code>docs/security.md</code></td></tr><tr><td></td><td>Feature roadmap</td><td>✅ <code>FEATURE_RECOMMENDATIONS.md</code></td></tr><tr><td></td><td>Versioning / deprecation policy</td><td>✅ <code>docs/versioning.md</code></td></tr><tr><td></td><td>Browser support matrix</td><td>✅ <code>docs/browser-support.md</code></td></tr><tr><td></td><td>Accessibility contract documented</td><td>✅ <code>docs/accessibility.md</code></td></tr><tr><td><strong>Governance</strong></td><td>LICENSE</td><td>✅ MIT</td></tr><tr><td></td><td>CODEOWNERS</td><td>⚠️ Structure in place — placeholder handles still need real team mapping</td></tr><tr><td></td><td>CONTRIBUTING guide</td><td>✅ <code>CONTRIBUTING.md</code></td></tr><tr><td></td><td>Code of Conduct</td><td>✅ <code>CODE_OF_CONDUCT.md</code> (Contributor Covenant 2.1)</td></tr><tr><td></td><td>Issue / PR templates</td><td>✅ <code>.github/ISSUE_TEMPLATE/*</code>, <code>.github/PULL_REQUEST_TEMPLATE.md</code></td></tr><tr><td><strong>Security</strong></td><td>Documented threat model &amp; sandbox guidance</td><td>✅</td></tr><tr><td></td><td>Dependency updates (Dependabot)</td><td>✅</td></tr><tr><td></td><td>Static security scanning (CodeQL)</td><td>✅ <code>.github/workflows/codeql.yml</code></td></tr><tr><td></td><td>Secret scanning / push protection</td><td>⚠️ Requires a one-time toggle in repo Settings — not something a workflow file can enable; see Phase 2 note below</td></tr><tr><td></td><td>Vulnerability disclosure process (<code>SECURITY.md</code>)</td><td>✅ <code>SECURITY.md</code></td></tr><tr><td></td><td>Dependency license compliance scan</td><td>✅ <code>npm run license:check</code>, wired into CI</td></tr><tr><td><strong>Release engineering</strong></td><td>CI pipeline (lint/typecheck/coverage/build/docs)</td><td>✅</td></tr><tr><td></td><td>Automated versioning + changelog (release-it)</td><td>✅ configured</td></tr><tr><td></td><td><code>CHANGELOG.md</code> committed and populated</td><td>✅ Seeded for <code>1.0.0</code>; auto-generated from here on</td></tr><tr><td></td><td>npm provenance / signed publishes</td><td>✅ <code>publishConfig.provenance</code> + <code>--provenance</code> publish arg; CI already had <code>id-token: write</code></td></tr><tr><td></td><td>SBOM (software bill of materials)</td><td>❌ Missing — not attempted in Phases 1-3</td></tr><tr><td><strong>Accessibility</strong></td><td><code>title</code> documented as required</td><td>✅</td></tr><tr><td></td><td>Automated accessibility testing</td><td>✅ <code>tests/IframeWrapper.a11y.spec.ts</code> + <code>demo/tests/App.a11y.spec.ts</code> (axe-core via jsdom)</td></tr><tr><td></td><td>Real-browser / assistive-tech-level a11y testing</td><td>✅ <code>tests-e2e/accessibility.spec.ts</code> + <code>demo-accessibility.spec.ts</code> (<code>@axe-core/playwright</code>, real keyboard Tab-order)</td></tr><tr><td><strong>Cross-browser confidence</strong></td><td>Real-browser E2E tests</td><td>✅ Playwright across Chromium/Firefox/WebKit — see Phase 4 below</td></tr><tr><td></td><td>Visual regression tests</td><td>✅ 4 scenarios, pinned browser/project, documented baseline-review process — see Phase 5 below</td></tr><tr><td><strong>Framework coverage</strong></td><td>SSR / Nuxt support verified</td><td>❌ Missing (SDS Phase 12, planned — Phase 6 below)</td></tr><tr><td><strong>Observability</strong></td><td>Structured error/event surface (<code>error</code>, <code>injected</code>)</td><td>✅ Library exposes hooks</td></tr><tr><td></td><td>Reference telemetry integration example</td><td>✅ <code>docs/guide/telemetry.md</code> (generic pattern, Sentry, HTTP beacon, reusable composable)</td></tr><tr><td><strong>Bundle health</strong></td><td>Bundle size tracked/budgeted in CI</td><td>✅ <code>size-limit</code>, wired into CI</td></tr></tbody></table><p><strong>Bottom line:</strong> Phases 1-5 are now fully implemented, including Phase 3&#39;s previously deferred demo-app accessibility test (which caught two real, since-fixed issues: both CSS/JS textareas had no accessible name, and the live event log wasn&#39;t announced to screen readers) and Phase 4&#39;s previously-open real-browser accessibility gap (now covered by <code>@axe-core/playwright</code> assertions plus genuine keyboard Tab-order tests, against both the harness and the demo app). A reference telemetry integration example (<code>docs/guide/telemetry.md</code>) is also done, closing the last Observability gap. Separately, all 13 items in <a href="/feature-recommendations"><code>FEATURE_RECOMMENDATIONS.md</code></a> are now implemented — new props (<code>allow</code>/<code>referrerPolicy</code>/<code>loading</code>/<code>allowFullscreen</code>/<code>autoHeight</code>), loading/error slots, asset load-status tracking, two new composables (<code>useIframeMessage</code>, <code>useIframeTheme</code>), a Vue Devtools inspector, and an SSR-safety audit that found and fixed a real bug. The remaining gap is the dedicated <code>@enterprise/nuxt-iframe-wrapper</code><strong>package</strong> specifically (Phase 6) — deliberately last, since it&#39;s the only item that opens a new long-term maintenance surface rather than hardening the existing one; the lower-effort SSR <em>guidance</em> alternative is done (see <a href="/guide/ssr">SSR / Nuxt Guidance</a>). Also still open: an SBOM (not yet attempted), and a handful of explicitly-noted manual, one-time actions: a repo-settings toggle for secret scanning, and real CODEOWNERS handles in place of the current placeholder.</p><hr><h2 id="phased-plan-—-easiest-to-hardest" tabindex="-1">Phased plan — easiest to hardest <a class="header-anchor" href="#phased-plan-—-easiest-to-hardest" aria-label="Permalink to &quot;Phased plan — easiest to hardest&quot;">​</a></h2><p>Effort estimates assume one engineer already familiar with this codebase. Each phase is independently shippable; none blocks the others except where noted.</p><h3 id="phase-1-—-governance-paperwork-hours-no-new-tooling-—-✅-implemented" tabindex="-1">Phase 1 — Governance paperwork (hours, no new tooling) — ✅ Implemented <a class="header-anchor" href="#phase-1-—-governance-paperwork-hours-no-new-tooling-—-✅-implemented" aria-label="Permalink to &quot;Phase 1 — Governance paperwork (hours, no new tooling) — ✅ Implemented&quot;">​</a></h3><p>The lowest-effort, highest-signal items for a procurement/security checklist. Pure documentation; no code or CI changes.</p><ul><li>[x] <code>SECURITY.md</code> — vulnerability disclosure process, supported versions, contact/SLA.</li><li>[x] <code>CONTRIBUTING.md</code> — how to run tests, coding standards, PR expectations (mostly restating what&#39;s already in <code>README.md</code>&#39;s Development section, formalized).</li><li>[x] <code>CODE_OF_CONDUCT.md</code> — Contributor Covenant 2.1.</li><li>[x] <code>.github/ISSUE_TEMPLATE/bug_report.md</code>, <code>feature_request.md</code>, and <code>config.yml</code>.</li><li>[x] <code>.github/PULL_REQUEST_TEMPLATE.md</code> — checklist including &quot;tests added&quot;, &quot;docs updated&quot;, &quot;changelog entry&quot;.</li><li>[ ] Replace the placeholder <code>@enterprise/ui-platform-team</code> handle in <code>CODEOWNERS</code> with real team/individual GitHub handles. <strong>Not done</strong> — requires real org/team names that don&#39;t exist in this exercise; the file now has an explicit <code>TODO(governance)</code> marker instead so it isn&#39;t missed.</li><li>[x] Add a <strong>Browser Support Matrix</strong> section to the docs (<code>docs/browser-support.md</code>).</li><li>[x] Add a <strong>Versioning &amp; Deprecation Policy</strong> section (<code>docs/versioning.md</code>).</li></ul><p><strong>Effort:</strong> XS (½–1 day total) · <strong>Unblocks:</strong> nothing else, but typically the #1 thing a procurement/security review asks for first.</p><p><strong>Status:</strong> Done except the CODEOWNERS handle replacement, which is intentionally left as a placeholder (see above) rather than filled with invented team names.</p><hr><h3 id="phase-2-—-release-supply-chain-hardening-1–2-days-—-✅-implemented" tabindex="-1">Phase 2 — Release &amp; supply-chain hardening (1–2 days) — ✅ Implemented <a class="header-anchor" href="#phase-2-—-release-supply-chain-hardening-1–2-days-—-✅-implemented" aria-label="Permalink to &quot;Phase 2 — Release &amp; supply-chain hardening (1–2 days) — ✅ Implemented&quot;">​</a></h3><p>Wiring, not judgment calls — mostly configuration on top of what already exists (<code>release-it</code>, GitHub Actions, Dependabot).</p><ul><li>[x] Generate and commit an initial <code>CHANGELOG.md</code> (seeded by hand for <code>1.0.0</code>, since <code>release-it</code>&#39;s conventional-changelog plugin — already configured in <code>.release-it.json</code> — only generates entries from here forward).</li><li>[x] Enable npm provenance on publish: <code>publishConfig.provenance: true</code> in <code>package.json</code>, <code>--provenance --access public</code> added to <code>release-it</code>&#39;s npm publish args. The release workflow already had <code>id-token: write</code>, required for this.</li><li>[x] Add a CodeQL workflow (<code>.github/workflows/codeql.yml</code>) for static security analysis on every PR and a weekly schedule.</li><li>[ ] Enable GitHub secret scanning + push protection. <strong>Not done</strong> — this is a repository <em>Settings</em> toggle (Settings → Code security), not something expressible in a committed workflow file; needs a repo admin to flip it on once.</li><li>[x] Add a dependency license-compliance check: <code>npm run license:check</code> (<code>license-checker-rseidelsohn</code> with an explicit SPDX allow-list), wired into CI. Scoped to <code>--production</code> dependencies only — the published package has an empty <code>dependencies</code> object and only a <code>vue</code> peer dependency, so this check is really guarding against a future runtime dependency introducing an incompatible license. Dev-only tooling (e.g. <code>jest-axe</code>&#39;s bundled <code>axe-core@3.5.6</code>, under MPL-2.0) is intentionally out of scope: it never ships in the published npm package, so its license doesn&#39;t carry redistribution obligations to consumers.</li><li>[x] Add a bundle-size budget check in CI: <code>npm run size</code> (<code>size-limit</code>), budgeted at 6 kB gzipped per bundle format — current actual size is ~1.6-1.9 kB brotli.</li></ul><p><strong>Effort:</strong> S · <strong>Unblocks:</strong> nothing else; independent of Phase 1.</p><p><strong>Status:</strong> Done except enabling GitHub&#39;s secret scanning / push protection, which is a one-click repository setting rather than code — flip it on under <strong>Settings → Code security and analysis</strong> the next time someone with admin access is in there.</p><hr><h3 id="phase-3-—-accessibility-automation-sds-phase-10-2–4-days-—-✅-implemented" tabindex="-1">Phase 3 — Accessibility automation (SDS Phase 10) (2–4 days) — ✅ Implemented <a class="header-anchor" href="#phase-3-—-accessibility-automation-sds-phase-10-2–4-days-—-✅-implemented" aria-label="Permalink to &quot;Phase 3 — Accessibility automation (SDS Phase 10) (2–4 days) — ✅ Implemented&quot;">​</a></h3><p>Lower effort than the E2E/visual-regression phases because it can piggyback on the <strong>existing jsdom-based Vitest setup</strong> rather than requiring new browser-automation infrastructure.</p><ul><li>[x] Add <code>axe-core</code> (via <code>jest-axe</code>&#39;s <code>axe()</code> runner) to a new <code>tests/IframeWrapper.a11y.spec.ts</code>. Note: <code>jest-axe</code>&#39;s own <code>toHaveNoViolations</code> matcher is built against Jest&#39;s matcher-context shape and throws under Vitest — the runner (<code>axe()</code>) works fine, but the matcher itself had to be reimplemented against Vitest&#39;s <code>expect.extend</code> API (see <code>tests/setup.ts</code>), consuming the same <code>AxeResults</code> shape.</li><li>[x] Assert: the rendered <code>&lt;iframe&gt;</code> has no <code>frame-title</code> violation when <code>title</code> is provided, and explicitly assert the violation <strong>is</strong> present when it&#39;s omitted (so the test would catch a regression that silently drops the binding).</li><li>[x] Extend the demo app&#39;s own test setup with an a11y smoke test — <code>demo/tests/App.a11y.spec.ts</code>, wired in via a <code>demo/tests/**/*.spec.ts</code> include pattern and a <code>@enterprise/vue-iframe-wrapper</code> alias added to <code>vitest.config.ts</code>. This immediately caught a real, pre-existing issue: <strong>both CSS/JS <code>&lt;textarea&gt;</code> controls had no accessible name at all</strong> (a heading above each, but no <code>&lt;label&gt;</code>/<code>aria-labelledby</code> association) — fixed with <code>aria-labelledby</code> pointing at each heading&#39;s new <code>id</code>. Also added <code>aria-live=&quot;polite&quot;</code> to the event tape so screen readers announce new entries, which axe doesn&#39;t flag as a violation but is a real usability gap for the keyboard/screen-reader users this app&#39;s own accessibility test now covers.</li><li>[x] Document the accessibility contract explicitly — <code>docs/accessibility.md</code>.</li></ul><p><strong>Effort:</strong> M (lower end) · <strong>Depends on:</strong> nothing. <strong>Unblocks:</strong> nothing, but is a prerequisite for a credible accessibility statement in Phase 1&#39;s procurement paperwork.</p><p><strong>Status:</strong> Fully implemented. 53 tests total across both the library (<code>tests/</code>) and demo (<code>demo/tests/</code>) suites, including 9 a11y-specific cases (3 library + 6 demo), coverage gate still holds at 90%+ (demo tests are excluded from the coverage calculation itself, since <code>demo/</code> isn&#39;t a published artifact — only its accessibility regressions are worth catching, not its code coverage).</p><hr><h3 id="addendum-—-mutation-testing-stryker-—-✅-implemented-beyond-the-original-plan" tabindex="-1">Addendum — Mutation testing (Stryker) — ✅ Implemented, beyond the original plan <a class="header-anchor" href="#addendum-—-mutation-testing-stryker-—-✅-implemented-beyond-the-original-plan" aria-label="Permalink to &quot;Addendum — Mutation testing (Stryker) — ✅ Implemented, beyond the original plan&quot;">​</a></h3><p>Not one of the original six phases, but implemented alongside them because it directly strengthens the claim the Phase 1-3 checkmarks above are making: coverage percentages prove code <em>executed</em>, not that a regression would actually be <em>caught</em>. Added here rather than as a new numbered phase since it&#39;s a testing-quality investment orthogonal to the paperwork/E2E/SSR axis the six phases are organized around.</p><ul><li>[x] <code>stryker.config.json</code> — Vitest test runner, scoped to <code>src/utils/**/*.ts</code> and <code>src/composables/**/*.ts</code> only. <strong>Not</strong> <code>.vue</code> files (Stryker&#39;s mutator doesn&#39;t reliably parse Single-File Components) or <code>src/types/iframe.ts</code> (no runtime behavior to mutate) — see <a href="/guide/testing">Testing → Mutation testing</a> for the full rationale.</li><li>[x] <code>npm run mutation</code> script; <code>.github/workflows/mutation.yml</code> runs it on pushes to <code>main</code> touching the scoped files, weekly on a schedule, and on manual dispatch — deliberately <strong>not</strong> on every PR, since a full run takes minutes even on the smaller scoped file set (this sandbox&#39;s single CPU core made that especially visible, but the cost is real on any machine, just less extreme).</li><li>[x] Break threshold set to 60 (comfortable headroom under the ~82-86% actually measured), high/low informational thresholds at 80/60.</li></ul><p><strong>Status:</strong> Fully implemented and genuinely run to completion multiple times in this sandbox (unlike Phase 4/Playwright, mutation testing needs no browser download, so nothing was blocked here). Real, actionable findings came out of it, not just a score: a dead conditional branch in <code>insertOrReplace</code> was removed (every mutation of its condition survived because the branch body was a no-op), and several <code>inject*IntoDocument</code> tests were strengthened to assert the returned <code>id</code>/<code>type</code>/ <code>placement</code> metadata and default option values, not just the resulting DOM. Final scores: <strong>~86%</strong> on <code>iframe-injection.ts</code>, <strong>~82%</strong> on <code>useIframeInjection.ts</code>. Two categories of survivor are documented as accepted rather than chased further: string-literal mutants on human-readable error message text, and one defensive <code>resolveParent</code> guard against a missing <code>&lt;head&gt;</code>/<code>&lt;body&gt;</code> that no realistic <code>Document</code> triggers.</p><hr><h3 id="phase-4-—-real-browser-e2e-suite-sds-phase-9-1–2-weeks-—-✅-implemented" tabindex="-1">Phase 4 — Real-browser E2E suite (SDS Phase 9) (1–2 weeks) — ✅ Implemented <a class="header-anchor" href="#phase-4-—-real-browser-e2e-suite-sds-phase-9-1–2-weeks-—-✅-implemented" aria-label="Permalink to &quot;Phase 4 — Real-browser E2E suite (SDS Phase 9) (1–2 weeks) — ✅ Implemented&quot;">​</a></h3><p>Meaningfully higher effort than Phase 3: requires standing up new tooling (<code>@playwright/test</code>), a browser matrix, and CI runners with real browser engines — jsdom cannot verify actual <code>sandbox</code> attribute enforcement or genuine cross-origin behavior.</p><ul><li>[x] Add <code>@playwright/test</code>, configure a <code>tests-e2e/</code> project separate from the existing Vitest unit suite. Built on a dedicated harness app (<code>tests-e2e/harness/</code>) rather than reusing <code>demo/</code> directly, so scenarios are driven by URL query params instead of UI interaction — see <a href="/guide/testing">Testing → End-to-end tests</a>.</li><li>[x] Cover: same-origin injection against Chromium/Firefox/WebKit (<code>injection.spec.ts</code>), <code>sandbox</code> enforcement — <code>window.open()</code> and form-submission blocking/permitting (<code>sandbox.spec.ts</code>), the <code>reloadKey</code> flow against real navigation/<code>load</code> timing (<code>reload.spec.ts</code>), and a genuine cross-origin case via a second server on a different port (<code>cross-origin.spec.ts</code>).</li><li>[x] Add a CI job running the Playwright suite (<code>.github/workflows/e2e.yml</code>), separate from the unit-test job, installing browsers with <code>--with-deps</code>.</li><li>[x] This is also the natural place to validate the Browser Support Matrix committed in Phase 1 with actual evidence instead of an assertion — the project matrix in <code>playwright.config.ts</code> (chromium/firefox/webkit) matches <code>docs/browser-support.md</code>.</li><li>[x] Extended beyond the original Phase 4 scope with dedicated accessibility assertions (<code>accessibility.spec.ts</code>, <code>demo-accessibility.spec.ts</code>) using <code>@axe-core/playwright</code> — real computed accessibility roles, real color-contrast calculation, and genuine keyboard Tab-order/focus behavior, none of which jsdom can verify. Closes the &quot;Real-browser / assistive-tech-level a11y testing&quot; gap left open after Phase 3. Required adding a third <code>webServer</code> entry (the demo app itself, not just the harness) so the demo&#39;s actual controls could be tested.</li></ul><p><strong>Effort:</strong> M–L · <strong>Depends on:</strong> nothing structurally, but is naturally sequenced after Phase 3 since both touch the test strategy and are easier to review together. <strong>Unblocks:</strong> Phase 5 (visual regression reuses this harness).</p><p><strong>Status:</strong> Implemented and validated as far as this sandboxed environment allows. <code>npx playwright test --list</code> confirms all 61 tests (across 7 spec files, 3 browser projects plus the pinned <code>visual</code> project) parse and discover correctly, <code>vue-tsc</code>/ ESLint pass over the harness and spec files, and the harness app itself was confirmed to boot and correctly resolve <code>@enterprise/vue-iframe-wrapper</code> via a raw HTTP check against its dev server. <strong>What could not be validated here:</strong> actually launching a browser and running the suite — this development sandbox&#39;s network egress allowlist does not include <code>cdn.playwright.dev</code>, which <code>npx playwright install</code> needs to download browser binaries. <code>.github/workflows/e2e.yml</code> runs <code>npx playwright install --with-deps</code> in GitHub Actions, which has normal internet access, so the real first execution will happen there (or in any local dev environment without that restriction) — this is a gap in <em>this sandbox&#39;s</em> validation, not a gap in the suite itself.</p><hr><h3 id="phase-5-—-visual-regression-testing-sds-phase-11-2–3-weeks-then-ongoing-—-✅-implemented" tabindex="-1">Phase 5 — Visual regression testing (SDS Phase 11) (2–3 weeks, then ongoing) — ✅ Implemented <a class="header-anchor" href="#phase-5-—-visual-regression-testing-sds-phase-11-2–3-weeks-then-ongoing-—-✅-implemented" aria-label="Permalink to &quot;Phase 5 — Visual regression testing (SDS Phase 11) (2–3 weeks, then ongoing) — ✅ Implemented&quot;">​</a></h3><p>Builds directly on Phase 4&#39;s Playwright harness, so the marginal setup cost is lower than starting from scratch — this phase has the highest <em>ongoing</em> maintenance cost of the group, since every intentional visual change requires reviewing and re-approving screenshot baselines, but the tooling and process are now both in place.</p><ul><li>[x] Add Playwright&#39;s built-in screenshot comparison (<code>toHaveScreenshot()</code>) — <code>tests-e2e/visual.spec.ts</code> now covers four scenarios (unstyled <code>srcdoc</code>, dark-themed CSS injection, light-themed CSS injection, JS-mutated content). Deliberately <strong>not</strong> covering an error/loading-slot state or an auto-height state — neither exists in the library yet (they&#39;re proposals in <code>FEATURE_RECOMMENDATIONS.md</code> #3/#4); add scenarios once either lands rather than committing baselines for features that don&#39;t exist.</li><li>[x] Establish a baseline-review process — <code>docs/guide/visual-regression.md</code>. Covers: when a diff is expected vs. a real signal, how snapshot filenames encode project/platform (and why only the CI/Linux baseline is authoritative), the CODEOWNERS-based approval path, and — importantly — a note that raising <code>maxDiffPixelRatio</code> to silence flakiness is exactly the wrong fix, since a tolerance loose enough to hide flakiness is loose enough to hide a regression too.</li><li>[x] Run visual tests on a fixed browser/OS combination in CI to avoid font-rendering flakiness across runner images — a dedicated <code>visual</code> Playwright project (<code>playwright.config.ts</code>), pinned to Chromium at a fixed 1000×700 viewport; <code>chromium</code>/<code>firefox</code>/<code>webkit</code> explicitly ignore <code>visual.spec.ts</code> so it never runs three times for no cross-browser signal. <code>animations: &#39;disabled&#39;</code> is set globally to remove the most common source of unrelated flakiness.</li></ul><p><strong>Effort:</strong> L, with recurring cost · <strong>Depends on:</strong> Phase 4 (done). <strong>Unblocks:</strong> nothing else.</p><p><strong>Status:</strong> Implemented and validated as far as this sandboxed environment allows — same constraint as Phase 4. <code>npx playwright test --list --project=visual</code> (once browsers are installed) will discover all four scenarios under the pinned project; config and spec files pass typecheck/lint. <strong>What could not be validated here:</strong> actually generating baseline images, for the same reason Phase 4&#39;s suite couldn&#39;t be executed — this sandbox&#39;s network egress allowlist excludes <code>cdn.playwright.dev</code>, so no browser binary could be downloaded to run <code>--update-snapshots</code> against. The first real baseline set will need to be generated in CI or a normal dev environment (see <code>docs/guide/visual-regression.md</code>) before <code>visual.spec.ts</code> can pass for the first time — until then, expect it to fail with &quot;no baseline found,&quot; which is the correct, expected state for a freshly-added visual suite, not a bug.</p><hr><h3 id="phase-6-—-ssr-nuxt-support-sds-phase-12-1-month-new-surface-to-maintain" tabindex="-1">Phase 6 — SSR / Nuxt support (SDS Phase 12) (1+ month, new surface to maintain) <a class="header-anchor" href="#phase-6-—-ssr-nuxt-support-sds-phase-12-1-month-new-surface-to-maintain" aria-label="Permalink to &quot;Phase 6 — SSR / Nuxt support (SDS Phase 12) (1+ month, new surface to maintain)&quot;">​</a></h3><p>The highest-effort item because it&#39;s not &quot;add tests to what exists&quot; but &quot;verify and support a lifecycle (SSR/hydration) the library has never been exercised against,&quot; potentially followed by a second published package.</p><ul><li>[ ] Audit the component for SSR-safety: confirm no <code>window</code>/<code>document</code> access happens outside lifecycle hooks or event handlers (a quick read of <code>IframeWrapper.vue</code> suggests this is already mostly true, but it&#39;s unverified — no SSR test exists).</li><li>[ ] Decide the integration shape: guidance-only (a documented <code>&lt;ClientOnly&gt;</code> pattern for Nuxt/Vite-SSR consumers) vs. a dedicated <code>@enterprise/nuxt-iframe-wrapper</code> module. Guidance-only is materially lower effort and should be attempted first.</li><li>[ ] If a dedicated module is warranted: new package, own versioning/release pipeline (duplicating much of Phases 1–2 for a second artifact), own test suite under Nuxt&#39;s test utils.</li><li>[ ] Document explicitly what &quot;SSR-safe&quot; means here: the library never executes injected JS during SSR — injection is a client-side DOM operation by design (see <code>docs/security.md</code>) — so there is no server-side sandboxing question, only a hydration-timing one.</li></ul><p><strong>Effort:</strong> XL · <strong>Depends on:</strong> nothing blocking, but lowest priority to start given the effort/uncertainty ratio — recommend validating real demand before committing to the dedicated-module path.</p><hr><h2 id="suggested-sequencing" tabindex="-1">Suggested sequencing <a class="header-anchor" href="#suggested-sequencing" aria-label="Permalink to &quot;Suggested sequencing&quot;">​</a></h2><p>Phases 1 and 2 have no dependencies on each other or on anything else and can run in parallel, ideally first — they&#39;re the fastest way to move the needle on a procurement checklist. Phase 3 is the next-cheapest quality investment. Phases 4 and 5 are naturally sequential (5 depends on 4&#39;s harness). Phase 6 is deliberately last: it&#39;s the only phase that opens a new long-term maintenance surface rather than hardening the existing one, and should be triggered by actual Nuxt/SSR demand rather than done speculatively.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase 1  Governance paperwork          ─┐  (parallel, no deps)</span></span>
<span class="line"><span>Phase 2  Release &amp; supply-chain        ─┘</span></span>
<span class="line"><span>Phase 3  Accessibility automation      ───→ (independent, cheap)</span></span>
<span class="line"><span>Phase 4  Playwright E2E                ───→ Phase 5 Visual regression</span></span>
<span class="line"><span>Phase 6  SSR / Nuxt support            ───→ (start only on validated demand)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>`,53)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
